import { type PropsWithChildren, useCallback } from 'react';
import { isElement } from 'react-is';

import { MARKER_HALF_WIDTH } from './value-marker-renderer/constants.js';
import { ValueMarkerRendererProps } from './value-marker-renderer/ValueMarkerRenderer.js';
import { useCanvas } from '../../../../canvas/hooks/useCanvas.js';
import { drawRoundRect } from '../../../../canvas/utils/drawRoundRect.js';
import {
  MARKER_BORDER_RADIUS,
  MARKER_ICON_OFFSET,
  MARKER_OPACITY,
  MARKER_STROKE_WIDTH,
} from '../../../constants.js';
import { useAnnotationsIconImages } from '../../../hooks/useAnnotationsIconImages.js';
import { CANVAS_PIXEL_OFFSET } from '../constants.js';
import { applyMarkerStyles } from '../utils/apply-marker-styles.js';
import { renderIconContent } from '../utils/render-icon-to-canvas.js';
import { renderTextContent } from '../utils/render-text-in-canvas.js';

const CONTENT_OFFSET_Y = 10;

export const RangeMarkerRenderer = (
  props: PropsWithChildren<ValueMarkerRendererProps>,
) => {
  const {
    height,
    width,
    x,
    y,
    fillColor,
    children,
    opacity = MARKER_OPACITY,
    brightness,
    strokeColor,
  } = props;

  const iconImages = useAnnotationsIconImages();

  const draw = useCallback(
    (ctx: CanvasRenderingContext2D) => {
      ctx.beginPath();
      const rectX = x;
      const rectY = y - MARKER_STROKE_WIDTH - CANVAS_PIXEL_OFFSET;
      const rectWidth = width;
      const rectHeight = height + MARKER_STROKE_WIDTH * 2 - CANVAS_PIXEL_OFFSET;

      drawRoundRect(
        ctx,
        rectX,
        rectY,
        rectWidth,
        rectHeight,
        MARKER_BORDER_RADIUS,
      );
      applyMarkerStyles(ctx, opacity, brightness, fillColor, strokeColor);
      ctx.closePath();

      if (isElement(children)) {
        const iconX = x + width / 2 - MARKER_HALF_WIDTH + MARKER_ICON_OFFSET;
        const iconY = y + MARKER_ICON_OFFSET;

        renderIconContent(ctx, children, iconImages, iconX, iconY);
      } else if (typeof children === 'string') {
        const textX = x + width / 2;
        renderTextContent(
          ctx,
          children,
          textX,
          y + CONTENT_OFFSET_Y,
          'center',
          fillColor,
        );
      }

      return false;
    },
    [
      x,
      y,
      width,
      height,
      opacity,
      brightness,
      fillColor,
      strokeColor,
      children,
      iconImages,
    ],
  );

  useCanvas('annotations-range-marker', draw);

  return null;
};

RangeMarkerRenderer['displayName'] = 'RangeMarkerRenderer';
